    `   Space to reclaim: ${plan.spaceSavedMB.toFixed(2)}MB`
  );
  console.log(
    `   Status: ${dryRun ? "DRY-RUN - No changes made" : "READY TO EXECUTE"}`
  );

  process.exit(0);
}

main().catch((error) => {
  console.error("Error:", error.message);
  process.exit(1);
});
